129	  }, [modelId, setActivity, setComments]);
130	
131	  useEffect(() => {
132	    void fetchBuildingPresets()
133	      .then((ids) => {
134	        if (ids.length) setCodePresetIds(ids);
135	      })
136	      .catch((err) => log.error('bootstrap', 'fetchBuildingPresets failed', err));
137	  }, []);
138	
139	  useEffect(() => {
140	    const isEmpty = Object.keys(elementsById).length === 0;
141	    if (!isEmpty) return;
142	    void insertSeedHouse();
143	    return () => {
144	      wsRef.current?.close();
145	      wsRef.current = null;
146	    };
147	    // Run-once bootstrap: re-running is the user's job via the empty-state CTA.
148	    // eslint-disable-next-line react-hooks/exhaustive-deps
149	  }, []);
150	
151	  // Presence heartbeat — sends viewer/selection state to collaborators every ~2.3s
152	  useEffect(() => {
153	    const id = window.setInterval(() => {
154	      const ws = wsRef.current;
155	      if (!ws || ws.readyState !== WebSocket.OPEN) return;
156	      const st = useBimStore.getState();
157	      ws.send(
158	        JSON.stringify({
159	          type: 'presence_update',
160	          peerId: st.peerId,
161	          userId: st.userId,
162	          name: st.userDisplayName,
163	          selectionId: st.selectedId,
164	          viewer: st.viewerMode,
165	        }),
166	      );
167	    }, 2300);
168	    return () => window.clearInterval(id);
169	  }, []);
170	
171	  return { insertSeedHouse, seedLoading, seedError, setSeedError, wsOn, codePresetIds };
172	}

